@Configuration
class KafkaProducerConfig {

    @Value("${kafka.bootstrap.servers:localhost:9092}")
    private String bootstrapServers;

    @Value("${kafka.producer.acks:all}")
    private String acks;

    @Value("${kafka.producer.retries:3}")
    private int retries;

    @Value("${kafka.producer.enable.idempotence:true}")
    private boolean enableIdempotence;

    @Bean
    public KafkaProducer<String, String> kafkaProducer() {
        Properties props = new Properties();
        props.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        props.put(ProducerConfig.ACKS_CONFIG, acks);
        props.put(ProducerConfig.RETRIES_CONFIG, retries);
        props.put(ProducerConfig.ENABLE_IDEMPOTENCE_CONFIG, enableIdempotence);
        props.put(ProducerConfig.MAX_IN_FLIGHT_REQUESTS_PER_CONNECTION, 5);
        props.put(ProducerConfig.DELIVERY_TIMEOUT_MS_CONFIG, 120000);
        props.put(ProducerConfig.REQUEST_TIMEOUT_MS_CONFIG, 30000);
        props.put(ProducerConfig.LINGER_MS_CONFIG, 5);
        props.put(ProducerConfig.BATCH_SIZE_CONFIG, 16384);
        props.put(ProducerConfig.BUFFER_MEMORY_CONFIG, 33554432);
        return new KafkaProducer<>(props);
    }
}

@Service
class HeaderValidationService {

    private static final Logger logger = LoggerFactory.getLogger(HeaderValidationService.class);

    // Allowlist of permitted header keys
    private static final Set<String> ALLOWED_HEADER_KEYS = Set.of(
            "tracking-id",
            "user-id",
            "correlation-id",
            "source-system",
            "event-type",
            "event-version",
            "content-type",
            "priority",
            "retry-count",
            "session-id",
            "request-id",
            "tenant-id"
    );

    // Allow custom metadata headers with a specific prefix
    private static final String CUSTOM_METADATA_PREFIX = "x-meta-";

    // Pattern for valid header key characters (alphanumeric, hyphens, underscores)
    private static final Pattern VALID_HEADER_KEY_PATTERN = Pattern.compile("^[a-zA-Z0-9][a-zA-Z0-9\\-_]{0,127}$");

    // Maximum header value length
    private static final int MAX_HEADER_VALUE_LENGTH = 8192;

    // Maximum number of headers per message
    private static final int MAX_HEADERS_COUNT = 20;

    // Pattern for valid topic names
    private static final Pattern VALID_TOPIC_PATTERN = Pattern.compile("^[a-zA-Z0-9._\\-]{1,249}$");

    public Map<String, String> validateAndSanitizeHeaders(Map<String, String> headers) {
        if (headers == null || headers.isEmpty()) {
            return Collections.emptyMap();
        }

        if (headers.size() > MAX_HEADERS_COUNT) {
            throw new IllegalArgumentException(
                    "Too many headers. Maximum allowed: " + MAX_HEADERS_COUNT);
        }

        Map<String, String> sanitizedHeaders = new LinkedHashMap<>();

        for (Map.Entry<String, String> entry : headers.entrySet()) {
            String key = entry.getKey();
            String value = entry.getValue();

            // Validate key
            if (key == null || key.isBlank()) {
                logger.warn("Skipping header with null or blank key");
                continue;
            }

            String normalizedKey = key.trim().toLowerCase();

            if (!VALID_HEADER_KEY_PATTERN.matcher(normalizedKey).matches()) {
                throw new IllegalArgumentException(
                        "Invalid header key format: " + sanitizeForLogging(key));
            }

            if (!isAllowedHeaderKey(normalizedKey)) {
                throw new IllegalArgumentException(
                        "Header key not in allowlist: " + sanitizeForLogging(normalizedKey));
            }

            // Validate value
            if (value == null) {
                logger.warn("Skipping header with null value for key: {}", sanitizeForLogging(normalizedKey));
                continue;
            }

            if (value.length() > MAX_HEADER_VALUE_LENGTH) {
                throw new IllegalArgumentException(
                        "Header value too long for key: " + sanitizeForLogging(normalizedKey) +
                                ". Maximum length: " + MAX_HEADER_VALUE_LENGTH);
            }

            // Sanitize value - remove control characters except common whitespace
            String sanitizedValue = sanitizeHeaderValue(value);

            sanitizedHeaders.put(normalizedKey, sanitizedValue);
        }

        return sanitizedHeaders;
    }

    public void validateTopic(String topic) {
        if (topic == null || topic.isBlank()) {
            throw new IllegalArgumentException("Topic must not be blank");
        }

        if (!VALID_TOPIC_PATTERN.matcher(topic.trim()).matches()) {
            throw new IllegalArgumentException("Invalid topic name format");
        }
    }

    private boolean isAllowedHeaderKey(String key) {
        return ALLOWED_HEADER_KEYS.contains(key) || key.startsWith(CUSTOM_METADATA_PREFIX);
    }

    private String sanitizeHeaderValue(String value) {
        // Remove control characters except tab, newline, carriage return
        StringBuilder sb = new StringBuilder(value.length());
        for (char c : value.toCharArray()) {
            if (c >= 0x20 || c == '\t' || c == '\n' || c == '\r') {
                sb.append(c);
            }
        }
        return sb.toString().trim();
    }

    private String sanitizeForLogging(String input) {
        if (input == null) return "null";
        // Prevent log injection
        return input.replaceAll("[\\r\\n\\t]", "_")
                .substring(0, Math.min(input.length(), 100));
    }
}

@Service
class KafkaEventProducerService {

    private static final Logger logger = LoggerFactory.getLogger(KafkaEventProducerService.class);

    private final KafkaProducer<String, String> kafkaProducer;
    private final HeaderValidationService headerValidationService;

    public KafkaEventProducerService(KafkaProducer<String, String> kafkaProducer,
                                     HeaderValidationService headerValidationService) {
        this.kafkaProducer = kafkaProducer;
        this.headerValidationService = headerValidationService;
    }

    public CompletableFuture<RecordMetadata> sendEvent(String topic, String key, String message,
                                                        Map<String, String> headers,
                                                        Map<String, String> httpHeaders) {
        // Validate topic
        headerValidationService.validateTopic(topic);

        // Validate and sanitize user-provided headers
        Map<String, String> sanitizedHeaders = headerValidationService.validateAndSanitizeHeaders(headers);

        // Build the ProducerRecord
        ProducerRecord<String, String> record = new ProducerRecord<>(topic.trim(), key, message);

        // Add sanitized user headers
        for (Map.Entry<String, String> entry : sanitizedHeaders.entrySet()) {
            record.headers().add(entry.getKey(),
                    entry.getValue().getBytes(StandardCharsets.UTF_8));
        }

        // Extract and add relevant HTTP headers (tracking-id, user-id, etc.)
        addHttpTrackingHeaders(record, httpHeaders);

        // Add system-generated headers
        addSystemHeaders(record);

        CompletableFuture<RecordMetadata> future = new CompletableFuture<>();

        kafkaProducer.send(record, (metadata, exception) -> {
            if (exception != null) {
                logger.error("Failed to send event to topic {}: {}",
                        sanitizeForLogging(topic), exception.getMessage());
                future.completeExceptionally(exception);
            } else {
                logger.info("Event sent successfully to topic={}, partition={}, offset={}",
                        metadata.topic(), metadata.partition(), metadata.offset());
                future.complete(metadata);
            }
        });

        return future;
    }

    private void addHttpTrackingHeaders(ProducerRecord<String, String> record,
                                         Map<String, String> httpHeaders) {
        if (httpHeaders == null) return;

        // Map of HTTP headers to Kafka header names
        Map<String, String> httpToKafkaHeaderMapping = Map.of(
                "x-tracking-id", "tracking-id",
                "x-user-id", "user-id",
                "x-correlation-id", "correlation-id",
                "x-request-id", "request-id",
                "x-session-id", "session-id",
                "x-tenant-id", "tenant-id"
        );

        for (Map.Entry<String, String> mapping : httpToKafkaHeaderMapping.entrySet()) {
            String httpHeaderKey = mapping.getKey();
            String kafkaHeaderKey = mapping.getValue();

            String value = httpHeaders.get(httpHeaderKey);
            if (value != null && !value.isBlank()) {
                // Only add if not already present from user-provided headers
                if (!hasHeader(record.headers(), kafkaHeaderKey)) {
                    String sanitized = sanitizeHeaderValueSimple(value);
                    if (sanitized.length() <= 256) { // Limit HTTP-sourced header values
                        record.headers().add(kafkaHeaderKey,
                                sanitized.getBytes(StandardCharsets.UTF_8));
                    }
                }
            }
        }
    }

    private void addSystemHeaders(ProducerRecord<String, String> record) {
        record.headers().add("produced-at",
                java.time.Instant.now().toString().getBytes(StandardCharsets.UTF_8));
        record.headers().add("producer-app",
                "event-tracking-service".getBytes(StandardCharsets.UTF_8));
        record.headers().add("message-id",
                UUID.randomUUID().toString().getBytes(StandardCharsets.UTF_8));
    }

    private boolean hasHeader(Headers headers, String key) {
        return headers.lastHeader(key) != null;
    }

    private String sanitizeHeaderValueSimple(String value) {
        return value.replaceAll("[\\x00-\\x1F\\x7F]", "").trim();
    }

    private String sanitizeForLogging(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n\\t]", "_")
                .substring(0, Math.min(input.length(), 100));
    }

    @PreDestroy
    public void shutdown() {
        logger.info("Shutting down Kafka producer...");
        if (kafkaProducer != null) {
            kafkaProducer.flush();
            kafkaProducer.close(java.time.Duration.ofSeconds(10));
        }
    }
}

@RestController
@RequestMapping("/api/v1/events")
class EventController {

    private static final Logger logger = LoggerFactory.getLogger(EventController.class);

    private final KafkaEventProducerService producerService;

    public EventController(KafkaEventProducerService producerService) {
        this.producerService = producerService;
    }

    @PostMapping
    public ResponseEntity<?> publishEvent(
            @Valid @RequestBody EventRequest request,
            @RequestHeader Map<String, String> httpHeaders) {

        try {
            // Filter HTTP headers to only include relevant ones
            Map<String, String> relevantHttpHeaders = filterRelevantHttpHeaders(httpHeaders);

            CompletableFuture<RecordMetadata> future = producerService.sendEvent(
                    request.getTopic(),
                    request.getKey(),
                    request.getMessage(),
                    request.getHeaders(),
                    relevantHttpHeaders
            );

            // Wait with timeout
            RecordMetadata metadata = future.get(30, TimeUnit.SECONDS);

            EventResponse response = new EventResponse(
                    "SUCCESS",
                    metadata.topic(),
                    metadata.partition(),
                    metadata.offset(),
                    java.time.Instant.ofEpochMilli(metadata.timestamp()).toString()
            );

            return ResponseEntity.ok(response);

        } catch (IllegalArgumentException e) {
            logger.warn("Validation error: {}", e.getMessage());
            return ResponseEntity.badRequest()
                    .body(new ErrorResponse("VALIDATION_ERROR", e.getMessage()));
        } catch (java.util.concurrent.TimeoutException e) {
            logger.error("Timeout sending event to Kafka");
            return ResponseEntity.status(HttpStatus.GATEWAY_TIMEOUT)
                    .body(new ErrorResponse("TIMEOUT", "Failed to send event within timeout period"));
        } catch (Exception e) {
            logger.error("Error publishing event: {}", e.getMessage(), e);
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body(new ErrorResponse("INTERNAL_ERROR", "Failed to publish event"));
        }
    }

    @PostMapping("/batch")
    public ResponseEntity<?> publishBatchEvents(
            @Valid @RequestBody List<@Valid EventRequest> requests,
            @RequestHeader Map<String, String> httpHeaders) {

        if (requests == null || requests.isEmpty()) {
            return ResponseEntity.badRequest()
                    .body(new ErrorResponse("VALIDATION_ERROR", "Request list must not be empty"));
        }

        if (requests.size() > 100) {
            return ResponseEntity.badRequest()
                    .body(new ErrorResponse("VALIDATION_ERROR", "Batch size must not exceed 100"));
        }

        Map<String, String> relevantHttpHeaders = filterRelevantHttpHeaders(httpHeaders);
        List<Map<String, Object>> results = new ArrayList<>();

        for (int i = 0; i < requests.size(); i++) {
            EventRequest request = requests.get(i);
            Map<String, Object> result = new LinkedHashMap<>();
            result.put("index", i);

            try {
                CompletableFuture<RecordMetadata> future = producerService.sendEvent(
                        request.getTopic(),
                        request.getKey(),
                        request.getMessage(),
                        request.getHeaders(),
                        relevantHttpHeaders
                );

                RecordMetadata metadata = future.get(30, TimeUnit.SECONDS);
                result.put("status", "SUCCESS");
                result.put("topic", metadata.topic());
                result.put("partition", metadata.partition());
                result.put("offset", metadata.offset());

            } catch (IllegalArgumentException e) {
                result.put("status", "FAILED");
                result.put("error", e.getMessage());
            } catch (Exception e) {
                result.put("status", "FAILED");
                result.put("error", "Failed to publish event");
            }

            results.add(result);
        }

        return ResponseEntity.ok(Map.of("results", results));
    }

    private Map<String, String> filterRelevantHttpHeaders(Map<String, String> httpHeaders) {
        if (httpHeaders == null) return Collections.emptyMap();

        Set<String> relevantPrefixes = Set.of("x-tracking-id", "x-user-id", "x-correlation-id",
                "x-request-id", "x-session-id", "x-tenant-id");

        return httpHeaders.entrySet().stream()
                .filter(e -> relevantPrefixes.contains(e.getKey().toLowerCase()))
                .collect(Collectors.toMap(
                        e -> e.getKey().toLowerCase(),
                        Map.Entry::getValue,
                        (v1, v2) -> v1
                ));
    }
}

